/**
 * Tests for the knotgraft client SDK.
 *
 * Uses a pure-function `fetch` mock so tests run without a live
 * endpoint. Covers: success path, octet-stream vs JSON transport,
 * auth header, 429 back-off with Retry-After, 401 / 413 errors,
 * chunked ingest, describe().
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import {
  KnotgraftClient,
  KnotgraftError,
  type KnotgraftResponse,
} from '../knotgraft-client';

// ─── Mock fetch factory ─────────────────────────────────────────────

interface Call {
  url: string;
  init: RequestInit;
}

function buildFetchMock(
  responder: (call: Call, callIndex: number) => Response,
): {
  fetch: typeof globalThis.fetch;
  calls: Call[];
} {
  const calls: Call[] = [];
  const mock: typeof globalThis.fetch = async (input, init) => {
    const url = typeof input === 'string' ? input : (input as URL | Request).toString();
    const idx = calls.length;
    calls.push({ url, init: init ?? {} });
    return responder({ url, init: init ?? {} }, idx);
  };
  return { fetch: mock, calls };
}

function okResponse(body: Partial<KnotgraftResponse> = {}): Response {
  const full: KnotgraftResponse = {
    blocks: 4,
    totalBytes: 256,
    lanesOccupied: 4,
    laneCount: 16,
    tenantHi: 1,
    tenantLo: 2,
    entries: [],
    throughputMBs: 1.0,
    rateLimit: { limitPerMinute: 600, remaining: 599, windowMs: 60_000 },
    ...body,
  };
  return new Response(JSON.stringify(full), {
    status: 200,
    headers: { 'content-type': 'application/json' },
  });
}

// ─── Tests ──────────────────────────────────────────────────────────

describe('KnotgraftClient', () => {
  describe('constructor', () => {
    it('requires a token', () => {
      expect(() =>
        new KnotgraftClient({ token: '' }),
      ).toThrow();
    });
  });

  describe('ingest — octet-stream transport', () => {
    it('sends raw bytes and includes bearer auth', async () => {
      const mock = buildFetchMock(() => okResponse());
      const client = new KnotgraftClient({
        baseUrl: 'http://edge.example',
        token: 'alpha',
        fetch: mock.fetch,
      });
      const bytes = new Uint8Array([1, 2, 3, 4]);
      const res = await client.ingest(bytes);
      expect(res.blocks).toBe(4);
      expect(mock.calls.length).toBe(1);
      expect(mock.calls[0]!.url).toBe('http://edge.example/api/knotgraft?k=16');
      expect(
        (mock.calls[0]!.init.headers as Record<string, string>)['Authorization'],
      ).toBe('Bearer alpha');
      expect(
        (mock.calls[0]!.init.headers as Record<string, string>)['Content-Type'],
      ).toBe('application/octet-stream');
      expect(mock.calls[0]!.init.body).toBeInstanceOf(Uint8Array);
    });

    it('honors laneCount and emitSql options via query params', async () => {
      const mock = buildFetchMock(() => okResponse());
      const client = new KnotgraftClient({
        baseUrl: 'http://edge.example',
        token: 'alpha',
        fetch: mock.fetch,
      });
      await client.ingest(new Uint8Array([1, 2, 3]), { laneCount: 8, emitSql: true });
      expect(mock.calls[0]!.url).toBe('http://edge.example/api/knotgraft?k=8&emitSql=1');
    });

    it('rejects invalid lane counts', async () => {
      const mock = buildFetchMock(() => okResponse());
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
      });
      await expect(client.ingest(new Uint8Array([1]), { laneCount: 0 })).rejects.toThrow();
      await expect(client.ingest(new Uint8Array([1]), { laneCount: 17 })).rejects.toThrow();
      await expect(client.ingest(new Uint8Array([1]), { laneCount: 1.5 })).rejects.toThrow();
    });
  });

  describe('ingest — JSON transport', () => {
    it('base64-encodes when forceJson is set', async () => {
      const mock = buildFetchMock(() => okResponse());
      const client = new KnotgraftClient({
        baseUrl: 'http://edge.example',
        token: 'alpha',
        fetch: mock.fetch,
      });
      await client.ingest(new Uint8Array([0x41, 0x42, 0x43]), { forceJson: true });
      const init = mock.calls[0]!.init;
      expect(
        (init.headers as Record<string, string>)['Content-Type'],
      ).toBe('application/json');
      const body = JSON.parse(init.body as string);
      expect(body.data).toBe('QUJD'); // base64 of "ABC"
      expect(body.laneCount).toBe(16);
    });
  });

  describe('ingest — errors', () => {
    it('throws KnotgraftError with status 401 on auth failure', async () => {
      const mock = buildFetchMock(() =>
        new Response(JSON.stringify({ error: 'Authentication required' }), {
          status: 401,
        }),
      );
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
      });
      try {
        await client.ingest(new Uint8Array([1]));
        expect(false).toBe(true); // unreachable
      } catch (err) {
        expect(err).toBeInstanceOf(KnotgraftError);
        expect((err as KnotgraftError).status).toBe(401);
      }
    });

    it('throws on 413 payload_too_large', async () => {
      const mock = buildFetchMock(() =>
        new Response(JSON.stringify({ error: 'payload_too_large' }), {
          status: 413,
        }),
      );
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
      });
      try {
        await client.ingest(new Uint8Array([1]));
        expect(false).toBe(true);
      } catch (err) {
        expect((err as KnotgraftError).status).toBe(413);
      }
    });
  });

  describe('429 back-off', () => {
    it('retries on 429 with Retry-After, then succeeds', async () => {
      let call = 0;
      const mock = buildFetchMock(() => {
        call += 1;
        if (call === 1) {
          return new Response(JSON.stringify({ error: 'rate_limited' }), {
            status: 429,
            headers: { 'Retry-After': '0' },
          });
        }
        return okResponse({ blocks: 7 });
      });
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
        maxRetries: 2,
      });
      const res = await client.ingest(new Uint8Array([1, 2, 3]));
      expect(res.blocks).toBe(7);
      expect(mock.calls.length).toBe(2);
    });

    it('gives up after maxRetries consecutive 429s', async () => {
      const mock = buildFetchMock(
        () =>
          new Response(JSON.stringify({ error: 'rate_limited' }), {
            status: 429,
            headers: { 'Retry-After': '0' },
          }),
      );
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
        maxRetries: 2,
      });
      try {
        await client.ingest(new Uint8Array([1]));
        expect(false).toBe(true);
      } catch (err) {
        expect(err).toBeInstanceOf(KnotgraftError);
        expect((err as KnotgraftError).status).toBe(429);
      }
      // 1 initial + 2 retries = 3 attempts
      expect(mock.calls.length).toBe(3);
    });
  });

  describe('ingestChunked', () => {
    it('splits payload into N ≤ chunkBytes requests', async () => {
      const mock = buildFetchMock(() => okResponse());
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
      });
      const bytes = new Uint8Array(250); // will split into 3 chunks of 100 + trailing 50
      for (let i = 0; i < bytes.length; i++) bytes[i] = i & 0xff;
      const results = await client.ingestChunked(bytes, 100);
      expect(results.length).toBe(3);
      expect(mock.calls.length).toBe(3);
    });

    it('rejects non-positive chunkBytes', async () => {
      const mock = buildFetchMock(() => okResponse());
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
      });
      await expect(
        client.ingestChunked(new Uint8Array([1, 2]), 0),
      ).rejects.toThrow();
    });
  });

  describe('describe', () => {
    it('returns tier and limits from GET', async () => {
      const mock = buildFetchMock(
        () =>
          new Response(
            JSON.stringify({
              tier: 'pro',
              limits: { requestsPerMinute: 600, maxRequestBytes: 16 * 1024 * 1024 },
            }),
            { status: 200 },
          ),
      );
      const client = new KnotgraftClient({
        token: 'alpha',
        fetch: mock.fetch,
      });
      const desc = await client.describe();
      expect(desc.tier).toBe('pro');
      expect(desc.limits.requestsPerMinute).toBe(600);
      expect(mock.calls[0]!.init.method).toBe('GET');
    });
  });
});
